import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"SITL","description":"Notes on SITL.","frontmatter":{"title":"SITL","description":"Notes on SITL."},"headers":[],"relativePath":"robotics/sitl-1.md","filePath":"robotics/sitl-1.md"}'),l={name:"robotics/sitl-1.md"};function r(s,e,n,c,h,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="sitl" tabindex="-1">SITL <a class="header-anchor" href="#sitl" aria-label="Permalink to &quot;SITL&quot;">​</a></h1><p><strong>SITL</strong> (Software In The Loop) runs autopilot firmware on your dev machine so you can test missions without airframe hardware.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://www.youtube.com/watch?v=mKt4ZTaE2bk" target="_blank" rel="noreferrer">YouTube: SITL basics</a></li></ul><h2 id="what-sitl-gives-you" tabindex="-1">What SITL gives you <a class="header-anchor" href="#what-sitl-gives-you" aria-label="Permalink to &quot;What SITL gives you&quot;">​</a></h2><ul><li>ArduPilot (or compatible stacks) built for desktop — physics simulated</li><li>Test <strong>DroneKit</strong>, MAVLink tools, and mission scripts from your IDE</li><li>Reproduce failsafes, RTL, and waypoint logic before flying</li></ul><h2 id="typical-workflow" tabindex="-1">Typical workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical workflow&quot;">​</a></h2><ol><li>Install ArduPilot SITL dependencies for your OS</li><li>Launch a simulated vehicle (copter/plane/rover profile)</li><li>Connect GCS (Mission Planner, QGroundControl) or Python via MAVLink on UDP/TCP</li><li>Iterate on code against the simulated MAV</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./sitl/README.html">SITL section</a></li><li><a href="./sitl/simulated-vehicle-sitl.html">Simulated Vehicle (SITL)</a></li><li><a href="./README.html">Robotics</a></li></ul>',10)])])}const m=a(l,[["render",r]]);export{f as __pageData,m as default};
